/// <summary>
/// Replicates price validation logic for Sales Order Confirmation.
/// </summary>
public boolean validate(Object _calledFrom)
{
    // 1. Execute the standard validation first
    boolean ret = next validate(_calledFrom);

    if(ETG_Parameters::find().UnitPriceValidation == NoYes::Yes)
    {
        if (ret)
        {
            // 'this' refers to the SalesFormLetter_Confirm instance
            SalesTable salesTable = this.salesTable();
            SalesLine  salesLine;

            // Note: Use 'LineNum' for SalesLine (PurchLine uses LineNumber)
            while select LineNum, SalesPrice from salesLine
            where salesLine.SalesId == salesTable.SalesId
            {
                if (!salesLine.SalesPrice)
                {
                    // Throw error and fail validation
                    ret = checkFailed(strFmt("Unit price must be filled for line %1.", salesLine.LineNum));
                    break;
                }
            }
        }
    }

    return ret;
}
